Here's a modern MSTest test class covering async patterns, timeouts, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: create a DataFetcher backed by a fake handler
    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    // --- Async + Timeout ---

    [TestMethod]
    [Timeout(5000)] // fails if test doesn't complete in 5 s
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello")
        });

        var fetcher = CreateFetcher(handler);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.InternalServerError
        });

        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- CancellationToken ---

    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        var handler = new FakeHandler(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        var fetcher = CreateFetcher(handler);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        // Handler cancels the token mid-flight
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(_ =>
        {
            cts.Cancel();
            throw new TaskCanceledException();
        });

        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Minimal fake HttpMessageHandler ---

    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, HttpResponseMessage> _factory;

        public FakeHandler(HttpResponseMessage fixedResponse)
            : this(_ => fixedResponse) { }

        public FakeHandler(Func<HttpRequestMessage, HttpResponseMessage> factory)
            => _factory = factory;

        // Action overload for side-effect-only callbacks (e.g. cancel + throw)
        public FakeHandler(Action<HttpRequestMessage> action)
            : this(req => { action(req); return null!; }) { }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_factory(request));
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` (never `async void`) |
| **Timeouts** | `[Timeout(ms)]` — MSTest cancels the test if it exceeds the limit |
| **Cancellation (pre-cancelled)** | Pass an already-cancelled token, assert `TaskCanceledException` |
| **Cancellation (mid-flight)** | Cancel inside the handler to simulate network interruption |
| **No real HTTP** | `FakeHandler` overrides `SendAsync` — no network needed |

> **Tip:** `[Timeout]` works by flowing a `CancellationToken` through `TestContext`. In MSTest 3.x+ you can also accept `CancellationToken` as a test method parameter for cooperative cancellation, but `[Timeout]` alone handles the common case.
